int* segment_tree_operations(int arr[], int size, int* out_size) {
    if (size < 1) {
        *out_size = 0;
        return NULL;
    }

    n = arr[0];
    if (n < 0 || size < 1 + n) {
        *out_size = 0;
        return NULL;
    }

    int remaining = size - 1 - n;
    if (remaining < 0 || (remaining % 3) != 0) {
        *out_size = 0;
        return NULL;
    }

    int q = remaining / 3;
    int* result = (int*)malloc((q > 0 ? q : 1) * sizeof(int));
    if (!result) {
        *out_size = 0;
        return NULL;
    }

    tree = (int *)calloc(4 * (n > 0 ? n : 1), sizeof(int));
    if (!tree) {
        free(result);
        *out_size = 0;
        return NULL;
    }

    build(arr + 1, 0, 0, n - 1);
    int pos = 1 + n;
    int result_count = 0;
    for (int i = 0; i < q; i++) {
        int type = arr[pos++];
        int a = arr[pos++];
        int b = arr[pos++];
        if (type == 1) {
            update(0, 0, n - 1, a, b);
        } else {
            result[result_count++] = query(0, 0, n - 1, a, b);
        }
    }

    free(tree);
    *out_size = result_count;
    return result;
}

