int constructUtil(int arr[],int ss,int se,int *st,int si){
	if(ss==se){
		st[si]=arr[ss];
		return arr[ss];
	}
	int mid = getMid(ss,se);
	st[si]=constructUtil(arr,ss,mid,st,2*si+1)+constructUtil(arr,mid+1,se,st,2*si+2);
	return st[si];
}

